        /* <flatten type="Javascript"> */
var f = this, field1 = f.getItem('rkey').field, field2 = f.getItem('rkey2').field, allowExt = 'gif,png,jpg,jpeg';
var imgname = getFileName($get('imageupload').value), imgname2 = getFileName($get('imageupload2').value);
var err = (f._language == 'v' ? 'Định dạng tệp ảnh không đúng.' : 'Invalid file type.');
var b0 = (imgname != ''), b1 = (imgname2 != ''), b2 = (f.getItemValue('imageurl') != ''), b3 = false;

if (b0) {
  var ext = imgname.split('.').pop();
  if (allowExt.indexOf(ext.toLowerCase()) < 0) {
    f._checked = false;
    $message.show(err);
  }
  else {
    var k = getRandomKey(12), h = f.getItemValue('ticket'), f1 = $get('uploadForm');
    f.setItemValue('rkey', k);
    f1.action = '../AppHandler/Image.ashx?t=upload&k=' + k + '&h=' + h;
    f1.submit();
    f1.reset();
  }
  field1.FilterSource = '';
}
else {
  f.setItemValue('rkey', '');
  field1.FilterSource = 'Ignore';
}

if ((f._checked) && (b1)) {
  var ext2 = imgname2.split('.').pop();
  if (allowExt.indexOf(ext2.toLowerCase()) < 0) {
    f._checked = false;
    $message.show(err);
  }
  else {
    if ((b0 != '') || ((b0 == '') && (b2))) {
      var k2 = getRandomKey(12), h2 = f.getItemValue('ticket2'), f2 = $get('uploadForm2');
      f.setItemValue('rkey2', k2);
      f2.action = '../AppHandler/Image.ashx?t=upload&k=' + k2 + '&h=' + h2;
      f2.submit();
      f2.reset();
    }
  }
  field2.FilterSource = '';
}
else {
  f.setItemValue('rkey2', '');
  field2.FilterSource = 'Ignore';
}

if (f._checked) {
  setEmployeeAddress(f);
}
/* </flatten> */

        &CheckValidEmailCommandChecking;
        &ListChecking;
        &PostChecking;

script.text:

function load$EmployeeForm(f) {
  var p = $get('empImage').parentNode;
  p.style.maxHeight = 'none';

  f.add_commandEvent(on$EmployeeForm$ExecuteCommand);
  f.add_onResponseComplete(on$EmployeeForm$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onChange$EmployeeForm$Tab);
  f._tabContainer._loaded = true;
  f._showFullImageHandler = Function.createDelegate(f, show$FormFullImage);

  $addHandler($get('imageupload'), 'change', onFileSelected);
  $addHandler(p, 'click', f._showFullImageHandler);

  init$EmployeeForm(f);
  f._textboxWatermark = ['dia_chi_ht_xa', 'dia_chi_ht_quan', 'dia_chi_ht_tinh', 'dia_chi_th_tru_xa', 'dia_chi_th_tru_quan', 'dia_chi_th_tru_tinh', 'que_quan_xa', 'que_quan_quan', 'que_quan_tinh'];
  textboxWatermark(f, f._textboxWatermark, 0, 'Region', 'c');
  objectBehavior$Dir$Code.create(f, 'stt', 'stt', 'hrnv');

      &ListCreate;
      &PostCreate;

}
function scatter$EmployeeForm(f) {
  loadEmployeeImage(f);
  init$EmployeeForm(f);

      &ListScattering;
      &PostScattering;
  textboxWatermark(f, f._textboxWatermark, 1);
}
function close$EmployeeForm(f) {
  textboxWatermark(f, f._textboxWatermark, 9);

      &ListDispose;
      &PostDispose;
  if (f._showFullImageHandler) try {$removeHandler($get('empImage').parentNode, 'click', f._showFullImageHandler);} catch (ex) {}
  try {$removeHandler($get('imageupload'), 'change', onFileSelected);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$EmployeeForm$Tab);} catch (ex) {}
  try {f.remove_onResponseComplete(on$EmployeeForm$ResponseComplete);} catch (ex) {}
  try {f.remove_commandEvent(on$EmployeeForm$ExecuteCommand);} catch (ex) {}
}
function on$EmployeeForm$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender;
  switch (action) {
    case 'Shown':
      setFormViewMode(f);
      &ListShown;
      &PostShown;
      break;
    case 'Save':
      f.getItem('ngay_tot_nghiep').field.AllowNulls = ($func.trim(f.getItemValue('ma_tdhv')) == '');
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function init$EmployeeForm(f) {
  var g = f.grid, o = f.getItem('tinh_trang_nv');
  var m = f.getItemValue('gioi_tinh'), d = g._view._activeDept;

  setFormViewMode(f);
  f.getItem('rights').value =  f._right;
  o.disabled = false;

  if (f._action == 'New') {
    $common.setVisible(o.a, true);
    o.value = f._statusID;
    f.getItem('ten_ttnv%l').value =  f._statusName;
    f.request('DefautFormValue', 'DefautFormValue', [['r', 'Decimal', f._right], ['ma_bp', 'String', d]]);
  }

  if (f._action == 'Edit') {
    var b = (f.getItemValue('rights') == 1), p = f.getItem('bo_phan');
    p.disabled = !b;
    $common.setVisible(p.a, b);

    b = $func.trim(o.value) == f._outWork;
    o.disabled = b;
    $common.setVisible(o.a, !b);
  }

  for (var i = 0; i < g._name.length; i++) {
    if (g._name[i][0] == m) {
      f.getItem('ten_gt').value = g._name[i][1];
      break;
    }
  }
}
function setFormViewMode(f) {
  var img = $get('empImage'), f1 = $get('imageupload'), f2 = $get('imageupload2');
  var viewMode = (f._action == 'View'), isBlank = (f._action == 'New') ;
  if (!isBlank) isBlank = ((f.getItemValue('imageurl') == '') && (f.getItemValue('rkey') == ''));

  f1.value = ''; f1.disabled = viewMode;
  f2.value = ''; f2.disabled = viewMode;
  f2.style.display = (viewMode || isBlank) ? 'none' : 'inline-block';
  img.parentNode.style.cursor = (viewMode && (!isBlank)) ? 'pointer' : 'default';
  img.style.display = isBlank ? 'none' : 'inline-block';
  if (isBlank) img.src = '';
}
function loadEmployeeImage(f) {
  var k = f.getItemValue('stt_rec'), src = f.getItemValue('imageurl');
  var o = $get('empImage'), p = o.parentNode, b = (f._action == 'New') || (src == '');
  p.parentNode.setAttribute('rowspan', 4);
  if (b) {
    p.className = 'ViewBlank';
    p.style.width = '58px';
    p.style.marginLeft = '1px';
  } else o.src = src;
}
function setViewPanelImage(f, v) {
  var g = f.grid, d = g._view._dirInfo;
  var img = '<img id="view_image" src="' + v + '">';
  if (!window.FileReader) $get('empImage').src = v;
  for (var i = 0; i < d.length; i++) {
    var id = d[i][0] + '_view_image';
    if ($get(id)) $get(id).innerHTML = img;
  }
}
function showBlankImage(f) {
  var id =  f._controller + '_view_image';
  if $get(id) $get(id).innerHTML = '<div class="ViewBlank"></div>';
}
function resetTicket(f, v, name) {
  f.setItemValue('ticket', v);
  if (name) f.focus(name);
}
function onFileSelected(e) {
  var img = $get('empImage'), parent = img.parentNode, ipt = $get('imageupload2');
  if (window.FileReader) {
    var reader = new FileReader(), file = e.target.files[0];
    reader.onload = function(e) { img.src = e.target.result; }
    if (file) reader.readAsDataURL(file);
  }
  else {
    img.src = '../Images/Attach.png';
  }
  img.style.height = '80px';
  img.style.display = 'inline-block';
  parent.className = 'FormContainer';
  parent.style.width = '100%';
  parent.style.margin = '0';
  ipt.style.display = 'inline-block';
}
function getFileName(s) {
  var p = s.lastIndexOf('\\');
  if (p != -1) {return s.substring(p + 1);}
  else {return s;}
}
function showViewPanelForm(f, t) {
  var g = f.grid, view = g._view;
  if (t) {
    if (view._controller) {
      if (view._type) view.showGridDetail();
      else window.setTimeout(function() {view.showViewPanel();}, 100);
    }
  }
  else {
    view.scatterMemvar(f);
  }
}
function setEmployeeAddress(f) {
  setItemAddress(f, 'dia_chi_ht', 'dia_chi_ht_so', 'dia_chi_ht_phuong');
  setItemAddress(f, 'dia_chi_th_tru', 'dia_chi_th_tru_so', 'dia_chi_th_tru_phuong');
  setItemAddress(f, 'que_quan', 'que_quan_so', 'que_quan_phuong');
}
function setItemAddress(f, name, c1, c2) {
  var c = $func.trim(f.getItemValue(c1)), d = $func.trim(f.getItemValue(c2));
  f.getItem(name).value = c + ((c != '') && (d != '') ? ' - ' : '') + d;
}
function getRandomKey(l) {
  var s = '', c = '0123456789abcdefghiklmnopqrstuvwxyz';
  for (var i = 0; i < l; i++) {
    var r = Math.floor(Math.random() * c.length);
    s += c.substring(r, r + 1);
  }
  return s;
}
function onChange$EmployeeForm$Gender(o) {
  var f = o.parentForm, g = f.grid, m = o.value;
  for (var i = 0; i < g._name.length; i++) {
    if (g._name[i][0] == m) {
      f.getItem('ten_gt').value = g._name[i][1];
      break;
    }
  }
}
function onChange$EmployeeForm$CurrentProvince(o) {
  var f = o.parentForm;
  f.setReferenceKeyFilter('dia_chi_ht_quan');
  f.setReferenceKeyFilter('dia_chi_ht_xa');
}
function onChange$EmployeeForm$CurrentDistrict(o) {o.parentForm.setReferenceKeyFilter('dia_chi_ht_xa'); }
function onChange$EmployeeForm$PermanentProvince(o) {
  var f = o.parentForm;
  f.setReferenceKeyFilter('dia_chi_th_tru_quan');
  f.setReferenceKeyFilter('dia_chi_th_tru_xa');
}
function onChange$EmployeeForm$PermanentDistrict(o) {o.parentForm.setReferenceKeyFilter('dia_chi_th_tru_xa');}
function onChange$EmployeeForm$NativeProvince(o) {
  var f = o.parentForm;
  f.setReferenceKeyFilter('que_quan_quan');
  f.setReferenceKeyFilter('que_quan_xa');
}
/* </flatten> */
function onChange$EmployeeForm$NativeDistrict(o) {o.parentForm.setReferenceKeyFilter('que_quan_xa');}
function onChange$EmployeeForm$Position(o) {o.parentForm.request('Position', 'Position', ['vi_tri'], o);}
function onChange$EmployeeForm$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['ngay_sinh','ngay_vao','ma_tdhv','ma_nn','dien_thoai_cty'&ListTabChange;&PostTabChange;,'nh_nv1']);&PostTabFocus;}
function onChange$EmployeeForm$Name(o) {var f = o.parentForm; f.getItem('ho_ten').value = $func.trim(f.getItem('ho_nv').value) + ' ' + $func.trim(f.getItem('ten_nv').value);}
function on$EmployeeForm$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Suggestion':
      var o = f._suggestionElement, v = (result[0].Value + 1).toString();
      if ($func.replace(o.field.DataFormatString, ' ', '').length >= v.length) {
        o.value = v;
        f.live(o);
      }
      break;
    case 'DefautFormValue':
      f.setItemValue('ticket', result[0].Value);
      f.setItemValue('ticket2', result[1].Value);
      f.setItemValue('ma_nv', result[2].Value);
      f.setItemControlBehavior('bo_phan', result[3].Value, result[4].Value, true);
      break;
    case 'Position':
      f.setItemControlBehavior('bac_quan_ly', result[0].Value, result[1].Value, true);
      f.live(f.getItem('bac_quan_ly'));
      break;
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_nv');
      break;
    &ListResponseTicket;
    default:
      break;
  }
}

      &ScriptSuggestion;
      &ListScript;
      &PostScript;
