dir.response:
&XMLSuggestion;
if exists(select 1 from hrvt where ma_vtr = @vi_tri and ma_bac <> '') begin declare @level varchar(32) select @level = ma_bac from hrvt where ma_vtr = @vi_tri select rtrim(@level) as ma_bac, ten_bac%l from hrdmbql where ma_bac = @level return end
&CreateTicket; &CreateTicket2; if @r = 1 and @ma_bp <> '' and exists(select 1 from hrbp where ma_bp = @ma_bp) begin declare @id varchar(32), @current varchar(32), @dept varchar(32), @ref varchar(32), @default varchar(32), @bp_ref varchar(128), @l1 int, @l2 int select @bp_ref = bp_ref from hrbp where ma_bp = @ma_bp if (@@admin = 1 ) or exists(select 1 from @@sysDatabaseName..hrquyenbp where user_id = @@userID and dbo.ff_Inlist(@bp_ref, r_access2) = 1) begin select @dept = @ma_bp, @current = @ma_bp select @id = rtrim(ma_ngam_dinh), @dept = bp_me from hrbp where ma_bp = @dept
while isnull(@id, '') = '' and @dept <> '' select @current = @dept, @id = rtrim(ma_ngam_dinh), @dept = bp_me from hrbp where ma_bp = @dept select @id = isnull(@id, '')
if @id <> '' begin select @ref = rtrim(bp_ref) + '%' from hrbp where ma_bp = @current select @default = max(ma_nv) from hrnv where ma_nv like (@id + '%') and bp_ref like @ref select @default = rtrim(isnull(@default, '')) select @l1 = len(@id), @l2 = len(@default) if @l2 > @l1 begin declare @numeric bit select @numeric = 1, @default = right(@default, @l2 - @l1) select @l1 = 1, @l2 = len(@default) while @numeric = 1 and @l1 <= @l2 select @numeric = case when ascii(substring(@default, @l1, 1)) between 48 and 57 then 1 else 0 end, @l1 = @l1 + 1 if @numeric = 1 select @id = @id + replace(str(cast(@default as bigint) + 1, len(@default)), ' ', '0') end end select @ticket as ticket, @ticket2 as ticket2, rtrim(@id) as id, @ma_bp as ma_bp, case @@language when 'v' then ten_bp else ten_bp2 end from hrbp where rtrim(ma_bp) = @ma_bp return end end else begin select @ticket as ticket, @ticket2 as ticket2, '' as id, '' as ma_bp, '' as ten_bp return end
&ListTicket;
